    std::vector<int> node_list_1 = {10, 20, 30};
    std::cout << node_list_1.at(9) << std::endl;
}

fix_solution:
#include <vector>
#include <iostream>
int main() {
    std::vector<int> node_list_1 = {10, 20, 30};
    if (node_list_1.size() > 9) {
        std::cout << node_list_1.at(9) << std::endl;
    }
}

